  1	import * as React from 'react';
  2	import { serverConfig } from '../../config';
  3	import { NEW_ISTIO_RESOURCE } from '../../pages/IstioConfigNew/IstioConfigNewPage';
  4	import { groupMenuStyle } from 'styles/DropdownStyles';
  5	import {
  6	  Dropdown,
  7	  DropdownGroup,
  8	  DropdownItem,
  9	  DropdownList,
 10	  MenuToggle,
 11	  MenuToggleElement
 12	} from '@patternfly/react-core';
 13	import { useKialiSelector } from 'hooks/redux';
 14	import { isParentKiosk, kioskContextMenuAction } from 'components/Kiosk/KioskActions';
 15	import { useKialiTranslation } from 'utils/I18nUtils';
 16	import { useNavigate } from 'react-router-dom-v5-compat';
 17	import { GroupVersionKind } from '../../types/IstioObjects';
 18	import { kindToStringIncludeK8s } from '../../utils/IstioConfigUtils';
 19	
 20	type ActionItem = {
 21	  action: React.ReactElement;
 22	  name: string;
 23	};
 24	
 25	export const IstioActionsNamespaceDropdown: React.FC = () => {
 26	  const kiosk = useKialiSelector(state => state.globalState.kiosk);
 27	  const { t } = useKialiTranslation();
 28	  const navigate = useNavigate();
 29	
 30	  const [dropdownOpen, setDropdownOpen] = React.useState<boolean>(false);
 31	
 32	  const onSelect = (): void => {
 33	    setDropdownOpen(!dropdownOpen);
 34	  };
 35	
 36	  const onToggle = (dropdownState: boolean): void => {
 37	    setDropdownOpen(dropdownState);
 38	  };
 39	
 40	  const onClickCreate = (gvk: GroupVersionKind): void => {
 41	    const newUrl = `/istio/new/${gvk.Group}/${gvk.Version}/${gvk.Kind}`;
 42	
 43	    if (isParentKiosk(kiosk)) {
 44	      kioskContextMenuAction(newUrl);
 45	    } else {
 46	      navigate(newUrl);
 47	    }
 48	  };
 49	
 50	  const isDisabled = (label: string, disabled: boolean): boolean => {
 51	    if (label.includes('K8s')) {
 52	      return !serverConfig.gatewayAPIEnabled;
 53	    } else if (label === t('Gateway')) {
 54	      return !serverConfig.istioGatewayInstalled;
 55	    } else if (label === t('ServiceEntry') || label === t('Sidecar')) {
 56	      return !serverConfig.istioAPIInstalled;
 57	    } else {
 58	      return disabled;
 59	    }
 60	  };
 61	
 62	  const dropdownItemsRaw = NEW_ISTIO_RESOURCE.map(
 63	    (r): ActionItem => {
 64	      const label = kindToStringIncludeK8s(r.value.Group, r.value.Kind);
 65	      return {
 66	        name: label,
 67	        action: (
 68	          <DropdownItem
 69	            key={`createIstioConfig_${label}`}
 70	            isDisabled={isDisabled(label, r.disabled)}
 71	            onClick={() => onClickCreate(r.value)}
 72	            data-test={`create_${label}`}
 73	          >
 74	            {label}
 75	          </DropdownItem>
 76	        )
 77	      };
 78	    }
 79	  );
 80	
 81	  const dropdownItems = [
 82	    <DropdownGroup
 83	      key={'group_create'}
 84	      label={t('Create')}
 85	      className={groupMenuStyle}
 86	      children={dropdownItemsRaw.map(r => r.action)}
 87	    />
 88	  ];
 89	
 90	  return (
 91	    <Dropdown
 92	      data-test="istio-actions-dropdown"
 93	      id="actions"
 94	      toggle={(toggleRef: React.Ref<MenuToggleElement>) => (
 95	        <MenuToggle
 96	          ref={toggleRef}
 97	          id="actions-toggle"
 98	          onClick={() => onToggle(!dropdownOpen)}
 99	          data-test="istio-actions-toggle"
100	          isExpanded={dropdownOpen}
101	        >
102	          {t('Actions')}
103	        </MenuToggle>
104	      )}
105	      isOpen={dropdownOpen}
106	      onOpenChange={(isOpen: boolean) => onToggle(isOpen)}
107	      onSelect={onSelect}
108	      popperProps={{ position: 'right' }}
109	    >
110	      <DropdownList>{dropdownItems}</DropdownList>
111	    </Dropdown>
112	  );
113	};

